use ethers::abi::{ParamType, Token, decode as abi_decode, encode as abi_encode};
use revm::{
    ExecuteCommitEvm, ExecuteEvm,
    context::{Context, TxEnv},
    database::InMemoryDB,
    handler::{MainBuilder, MainContext},
    primitives::{Address, Bytes, TxKind, U256},
};

/// Compiled bytecode of contracts/src/ERC20.sol
const ERC20_BYTECODE: &str = "";

type InMemoryEvm = revm::MainnetEvm<
    revm::context::Context<
        revm::context::BlockEnv,
        revm::context::TxEnv,
        revm::context::CfgEnv,
        InMemoryDB,
    >,
    (),
>;

fn init_evm() -> InMemoryEvm {
    Context::mainnet()
        .with_db(InMemoryDB::default())
        .modify_cfg_chained(|cfg| {
            cfg.set_spec_and_mainnet_gas_params(revm::primitives::hardfork::SpecId::PRAGUE);
            cfg.disable_balance_check = true;
            cfg.disable_nonce_check = true;
            cfg.disable_base_fee = true;
        })
        .build_mainnet()
}

/// Calls `balanceOf(holder)` on a deployed ERC20 contract and returns the balance.
fn balance_of(evm: &mut InMemoryEvm, contract: Address, holder: Address) -> U256 {
    // selector = keccak256("balanceOf(address)")[0..4] = 0x70a08231
    let selector = [0x70u8, 0xa0, 0x82, 0x31];
    let encoded_arg = abi_encode(&[Token::Address(ethers::types::H160::from(holder.0.0))]);
    let call_data: Bytes = [selector.as_ref(), encoded_arg.as_slice()].concat().into();

    let call_tx = TxEnv {
        caller: holder,
        kind: TxKind::Call(contract),
        data: call_data,
        gas_limit: 100_000,
        ..Default::default()
    };

    let output = evm
        .transact(call_tx)
        .expect("balanceOf call failed")
        .result
        .into_output()
        .expect("no output");

    let tokens = abi_decode(&[ParamType::Uint(256)], &output).expect("failed to decode balance");
    let ethers_u256 = tokens[0].clone().into_uint().expect("expected uint");

    // Convert ethers U256 (big-endian limbs) to alloy U256
    let mut bytes = [0u8; 32];
    ethers_u256.to_big_endian(&mut bytes);
    U256::from_be_bytes(bytes)
}

fn create_erc20_deploy_tx(
    deployer: Address,
    name: &str,
    symbol: &str,
    holders: &[Address],
    balances: &[U256],
) -> TxEnv {
    let holders: Vec<Token> = holders
        .iter()
        .map(|addr| Token::Address(ethers::types::H160::from(addr.0.0)))
        .collect();

    let balances: Vec<Token> = balances
        .iter()
        .map(|bal| {
            Token::Uint(ethers::types::U256::from_big_endian(
                &bal.to_be_bytes::<32>(),
            ))
        })
        .collect();

    let constructor_args = abi_encode(&[
        Token::String(name.to_string()),
        Token::String(symbol.to_string()),
        Token::Array(holders),
        Token::Array(balances),
    ]);

    let bytecode = revm::primitives::hex::decode(ERC20_BYTECODE).expect("invalid bytecode hex");
    let data: Bytes = [bytecode, constructor_args].concat().into();

    TxEnv {
        caller: deployer,
        kind: TxKind::Create,
        value: U256::ZERO,
        data,
        gas_limit: 5_000_000,
        ..Default::default()
    }
}

#[tokio::main]
async fn main() {
    let mut evm = init_evm();

    let deployer = Address::from([0x01u8; 20]);
    let holder = Address::from([0x02u8; 20]);
    let initial_supply = U256::from(1_000_000u64) * U256::from(10u64).pow(U256::from(18u64));

    let deploy_tx =
        create_erc20_deploy_tx(deployer, "MyToken", "MTK", &[holder], &[initial_supply]);

    let result = evm.transact_commit(deploy_tx).expect("deployment failed");

    println!("deploy result: {:?}", result);
    let contract_address = result.created_address().expect("contract not deployed");
    println!("ERC20 deployed at: {contract_address}");

    let balance = balance_of(&mut evm, contract_address, holder);
    println!("Balance of {holder}: {balance}");
}
